const token = $env.DOCMAIL_TOKEN;
const authHeader = $input.first().json.headers?.authorization || '';
const provided = authHeader.replace('Bearer ', '');

if (!token || provided !== token) {
  throw new Error('Unauthorized: invalid or missing token');
}

return $input.all();

const fs = require('fs');
const path = require('path');
const item = $input.first().json;

// Payload size validation (5MB max)
const content = item.body?.content || '';
if (Buffer.byteLength(content, 'utf8') > 5 * 1024 * 1024) {
  throw new Error('Payload too large: content exceeds 5MB limit');
}

// Filename sanitization: strip path components to prevent traversal
let filename = item.body?.filename || 'docmail_' + Date.now() + '.html';
filename = path.basename(filename);
if (!filename || filename === '.' || filename === '..' || filename.includes('\0')) {
  filename = 'unnamed_' + Date.now() + '.html';
}

// UPDATE THIS PATH to match your n8n server's docmail directory
const destDir = '/home/node/docmail';
const filePath = path.join(destDir, filename);

// Final check: resolved path must stay inside destDir
if (!path.resolve(filePath).startsWith(path.resolve(destDir) + path.sep) && path.resolve(filePath) !== path.resolve(destDir)) {
  throw new Error('Path traversal rejected');
}

fs.writeFileSync(filePath, content);

const subject = item.body?.subject || 'Document';

const fileBuffer = fs.readFileSync(filePath);

return [{
  json: {
    status: 'saved',
    path: filePath,
    filename,
    subject
  },
  binary: {
    file: {
      data: fileBuffer.toString('base64'),
      mimeType: 'text/html',
      fileName: filename
    }
  }
}];

const fs = require('fs');
const path = require('path');

// UPDATE THIS PATH to match your n8n server's docmail directory
const dir = '/home/node/docmail';
const archiveDir = '/home/node/docmail/archive';

if (!fs.existsSync(archiveDir)) {
  fs.mkdirSync(archiveDir, { recursive: true });
}

const saveData = $('Save Instant File').first().json;
let filename = saveData.filename;
const subject = saveData.subject;
if (filename) {
  // Defense in depth: re-sanitize even though Save Instant File already strips paths
  filename = path.basename(filename);
  if (!filename || filename === '.' || filename === '..' || filename.includes('\0')) {
    return [{ json: { status: 'instant_sent', subject: subject || 'Document', warning: 'invalid filename, archive skipped' } }];
  }
  const src = path.join(dir, filename);
  const dst = path.join(archiveDir, filename);
  if (fs.existsSync(src)) {
    fs.renameSync(src, dst);
  }
}

return [{ json: { status: 'instant_sent', subject: subject || 'Document' } }];

